const config = $input.first().json;
const items = [];

if (config.auto_send_due_soon) {
  items.push({ json: { lead_type: 'due_soon', max_leads: 4 } });
}
if (config.auto_send_passed) {
  items.push({ json: { lead_type: 'passed', max_leads: 4 } });
}

if (items.length === 0) {
  // Nothing enabled, stop execution
  return [];
}

return items;

const item = $input.first().json;

return [{
  json: {
    bridge_url: 'https://doris-bridge.yellowpond-051e3dca.eastus.azurecontainerapps.io',
    bridge_api_key: 'RapidScreenDoris',
    target_webhook: 'https://n8n-rapid-czbff9cnafhkhmhf.eastus-01.azurewebsites.net/webhook/tj-katsastus-outbound',
    max_leads_to_send: item.max_leads || 4,
    default_station_id: 58,
    lead_type: item.lead_type || 'both'
  }
}];

let overrideLeads = null;
let leadType = 'both';
try {
  const body = $('Dashboard Webhook')?.first()?.json?.body || {};
  overrideLeads = body.max_leads_to_send;
  if (body.lead_type) leadType = body.lead_type;
} catch(e) {}

return [{
  json: {
    bridge_url: 'https://doris-bridge.yellowpond-051e3dca.eastus.azurecontainerapps.io',
    bridge_api_key: 'RapidScreenDoris',
    target_webhook: 'https://n8n-rapid-czbff9cnafhkhmhf.eastus-01.azurewebsites.net/webhook/tj-katsastus-outbound',
    max_leads_to_send: overrideLeads || 50,
    default_station_id: 58,
    lead_type: leadType
  }
}];

const cfg = $('Build Config').first()?.json || $('Auto Build Config').first()?.json;
const existingRows = $input.all().map(i => i.json);

const excludedNumbers = [];
const excludedCustomerIds = [];
for (const r of existingRows) {
  if (r.number) excludedNumbers.push(String(r.number));
  if (r.customer_id != null) excludedCustomerIds.push(String(r.customer_id));
}

const startRes = await this.helpers.httpRequest({
  method: 'POST',
  url: `${cfg.bridge_url}/api/doris/inspection-leads`,
  headers: { 'X-API-Key': cfg.bridge_api_key },
  body: {
    excluded_numbers: excludedNumbers,
    excluded_customer_ids: excludedCustomerIds,
    max_leads: cfg.max_leads_to_send,
    default_station_id: cfg.default_station_id,
    lead_type: cfg.lead_type || 'both',
  },
  json: true,
  timeout: 15000,
});

if (!startRes?.success) {
  throw new Error('Failed to start scan: ' + JSON.stringify(startRes).slice(0, 500));
}

const jobId = startRes.data.job_id;

let result = null;
for (let i = 0; i < 40; i++) {
  await new Promise(r => setTimeout(r, 15000));
  const poll = await this.helpers.httpRequest({
    method: 'GET',
    url: `${cfg.bridge_url}/api/doris/inspection-leads/status/${jobId}`,
    headers: { 'X-API-Key': cfg.bridge_api_key },
    json: true,
    timeout: 15000,
  });
  if (!poll?.success && poll?.error) {
    throw new Error('Scan failed: ' + poll.error);
  }
  if (poll?.data?.status === 'done') {
    result = poll.data;
    break;
  }
}

if (!result) {
  throw new Error('Scan timed out after 10 minutes (job_id: ' + jobId + ')');
}

return [{
  json: {
    ...cfg,
    fetched_count: result.fetched_count,
    selected_count: result.selected_count,
    passed_count: result.passed_count,
    due_soon_count: result.due_soon_count,
    selection_stats: result.stats,
    fetch_errors: result.fetch_errors,
    customers_payload: { customers: result.leads },
  }
}];

const cfg = $('Fetch Inspection Leads').first().json;
const triggered = $input.first()?.json || {};

return [{
  json: {
    ok: true,
    mode: 'triggered',
    fetched_count: cfg.fetched_count,
    selected_count: cfg.selected_count,
    selection_stats: cfg.selection_stats,
    fetch_errors: cfg.fetch_errors,
    target_webhook: cfg.target_webhook,
    triggered_response: triggered
  }
}];

const cfg = $('Fetch Inspection Leads').first().json;

return [{
  json: {
    ok: true,
    mode: 'no_eligible_leads',
    fetched_count: cfg.fetched_count,
    selected_count: cfg.selected_count,
    selection_stats: cfg.selection_stats,
    fetch_errors: cfg.fetch_errors,
    target_webhook: cfg.target_webhook
  }
}];
